module RefModule(

    input clk_i,
    input rst_i,


    input do_wb_i,
    input [4:0] wb_reg_i,
    input [31:0] wb_val_i,


    output reg do_wb_o,
    output reg [4:0] wb_reg_o,
    output reg [31:0] wb_val_o
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk_i or posedge dbg_halt)
begin
    if (rst_i) begin
        do_wb_o <= 0;
        wb_reg_o <= 0;
        wb_val_o <= 0;
    end else begin
        do_wb_o <= do_wb_i;
        wb_reg_o <= wb_reg_i;
        wb_val_o <= wb_val_i;
    end
end

endmodule
